parameters.jsCode:
try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    let strategy;
    try {
      const text = item.json.content[0].text;
      strategy = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      if (match) {
        strategy = JSON.parse(match[0]);
      } else {
        strategy = {
          summary: 'Performance analysis complete',
          next_week_focus: 'Continue current approach',
          top_performing_channel: 'email',
          underperforming_areas: 'paid ads',
          updated_week1: 'Focus on content creation',
          updated_week2: 'Expand social media presence',
          updated_week3: 'Optimize ad campaigns',
          updated_week4: 'Review and scale winners',
          budget_adjustment: 'Maintain current budget',
          strategic_recommendations: ['Increase email frequency', 'Test new ad formats', 'Engage with audience comments']
        };
      }
    }
    const business = $node['Split In Batches'].json;
    results.push({json: {
      id: business.id,
      business_name: business.business_name || '',
      email: business.email || '',
      marketing_strategy: JSON.stringify(strategy),
      summary: strategy.summary || '',
      next_week_focus: strategy.next_week_focus || '',
      top_performing_channel: strategy.top_performing_channel || '',
      underperforming_areas: strategy.underperforming_areas || '',
      updated_week1: strategy.updated_week1 || '',
      updated_week2: strategy.updated_week2 || '',
      updated_week3: strategy.updated_week3 || '',
      updated_week4: strategy.updated_week4 || '',
      budget_adjustment: strategy.budget_adjustment || '',
      strategic_recommendations: strategy.strategic_recommendations || [],
      updated_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
